  INSERT INTO knowledge_sop_steps (sop_id, title, content, content_html, order_index, step_type) VALUES
  (v_sop_id, 'Objetivo', E'Integrar novos clientes à dinâmica TBO, reduzindo atritos de comunicação e alinhando expectativas desde o primeiro projeto. Um onboarding bem executado reduz conflitos por escopo, acelera aprovações e aumenta retenção. Meta: NPS > 70 após o primeiro projeto.', '', 0, 'step'),
  (v_sop_id, 'Escopo', E'**Quem executa:** Atendimento (Ruy Lima + responsável de conta) + Líder da BU\n**Quando se aplica:** Todo cliente novo, na assinatura do primeiro contrato\n**Limites:** Cobre integração inicial. Rituais contínuos → SOP tbo-atd-002. Reclamações → SOP tbo-atd-003.', '', 1, 'step'),
  (v_sop_id, 'RACI — Responsabilidades', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Enviar kit de boas-vindas | Atendimento | Ruy Lima | — | Marco Andolfato |\n| Configurar canais de comunicação | Atendimento | — | TI/Ops | Cliente |\n| Call de onboarding (30 min) | Ruy Lima | — | Líder BU | — |\n| Criar projeto + acessos no TBO OS | Ops | — | — | Atendimento, Cliente |\n| Check-in de 1 semana | Atendimento | — | — | Ruy Lima |\n| Retrospectiva de 30 dias | Ruy Lima | Marco | Cliente | — |', '', 2, 'step'),
  (v_sop_id, 'Pré-requisitos', E'- Contrato assinado\n- Kick-off de projeto realizado (SOP tbo-ops-003)\n- Projeto criado no TBO OS\n- E-mails e contatos do time do cliente coletados\n- Google Drive configurado\n- Kit de boas-vindas preparado', '', 3, 'step'),
  (v_sop_id, 'Procedimento', E'**D0: Kit de Boas-Vindas (mesmo dia da assinatura)**\nEnviar e-mail com: carta personalizada de Ruy, documento "Como trabalhamos", contatos da equipe TBO, link para Google Drive e agenda da call de onboarding.\n\n**D+2: Call de Onboarding (30-45 min)**\n1. Apresentar equipe TBO do projeto\n2. Explicar fluxo de trabalho TBO (briefing → produção → apresentação → aprovação)\n3. Alinhar expectativas mútuas (o que TBO precisa do cliente; o que cliente pode esperar)\n4. Confirmar canal de comunicação principal e ponto focal único\n5. Confirmar datas dos primeiros marcos\n\n**D0-D+2: Infraestrutura**\nDrive compartilhado + canal WhatsApp/Slack + acesso TBO OS + calendário recorrente (se projeto longo).\n\n**D+7: Check-in de 1 Semana**\nCall de 10-15 min. Verificar acesso às ferramentas, coletar primeira impressão, resolver fricções. Registrar satisfação (1-5) no TBO OS.\n\n**D+30: Retrospectiva**\nReunião 30-45 min. O que funcionou / o que melhorar / oportunidades de upsell.', '', 4, 'step'),
  (v_sop_id, 'Checklist de Validação', E'**D0:**\n- [ ] Kit de boas-vindas enviado\n- [ ] Call de onboarding agendada\n- [ ] Google Drive compartilhado\n- [ ] Canal de comunicação criado\n\n**D+2:**\n- [ ] Call de onboarding realizada\n- [ ] Ponto focal do cliente confirmado\n- [ ] Datas dos marcos alinhadas\n\n**D+7:**\n- [ ] Check-in realizado\n- [ ] Acesso às ferramentas confirmado\n- [ ] Satisfação registrada no TBO OS\n\n**D+30:**\n- [ ] Retrospectiva realizada\n- [ ] Oportunidades de upsell identificadas', '', 5, 'checkpoint'),
  (v_sop_id, 'Ferramentas e Recursos', E'- **TBO OS**: gestão de projeto, notas de conta\n- **Google Drive**: pasta compartilhada com cliente\n- **Google Calendar**: call de onboarding + recorrentes\n- **WhatsApp Business / Slack**: canal principal com cliente\n- **Gmail**: kit de boas-vindas e comunicações formais\n- **Template "Como Trabalhamos"**: Google Docs 1-pager', '', 6, 'tip'),
  (v_sop_id, 'SLAs e Métricas', E'| Métrica | Meta |\n|---|---|\n| Kit de boas-vindas enviado | D0 (mesmo dia da assinatura) |\n| Call de onboarding realizada | D+2 |\n| Check-in de 1 semana | D+7 |\n| Retrospectiva de 30 dias | D+30 |\n| Satisfação no check-in D+7 | ≥ 4/5 |\n| NPS após primeiro projeto | > 70 |\n| Taxa de renovação após 1º projeto | > 50% |', '', 7, 'note'),
  (v_sop_id, 'Troubleshooting', E'**Cliente não responde ao kit:** Follow-up por WhatsApp em D+2. Não é sinal negativo — cliente pode estar ocupado.\n\n**Múltiplos pontos focais (decisão por comitê):** Mapear comitê, identificar voto de minerva. Criar protocolo de aprovação por e-mail com prazo de 3 dias.\n\n**Cliente questiona o processo TBO:** Ouvir com atenção. Adaptar comunicação, não o processo. Ruy conduz com leveza.\n\n**Projeto atrasou — cliente sumiu depois de assinar:** Mini-onboarding reativo (20 min) para realinhar. Revisar briefing para dados desatualizados.', '', 8, 'warning'),
  (v_sop_id, 'Templates Prontos para Uso', E'**E-mail de Boas-Vindas:**\n```\nAssunto: Bem-vindo à TBO — tudo pronto para começar, [Nome]!\n\nOlá [Nome], é com satisfação que iniciamos a parceria no [Empreendimento].\n\n1. Como trabalhamos: [link]\n2. Equipe TBO neste projeto: [nomes + funções]\n3. Pasta do projeto no Drive: [link]\n4. Canal de comunicação: [link]\n5. Call de onboarding: [data/hora ou Calendly]\n\nRetornamos feedbacks em até 24h úteis. Esperamos aprovações em até 3 dias úteis.\n\nRuy Lima | Diretor Comercial TBO\n```\n\n**Notas D+7 (template):**\nDrive ✓/✗ | Canal ✓/✗ | TBO OS ✓/N/A\nSatisfação: /5 | Funcionando bem: | Fricções: | Pendências:', '', 9, 'tip');

  -- ══════════════════════════════════════════════════════════════════════════
  -- MELHORIA 4: Financeiro — Contas a Pagar e Controle de Despesas
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Contas a Pagar e Controle de Despesas',
    'tbo-fin-002-contas-a-pagar-e-controle-de-despesas',
    'financeiro',
    'processo',
    'Processo de gestão de contas a pagar, controle de despesas operacionais e aprovação de pagamentos na TBO, garantindo fluxo de caixa saudável, compliance fiscal e visibilidade financeira por centro de custo.',
    E'## Contas a Pagar e Controle de Despesas\n\n### 1. Objetivo\nGarantir que todas as obrigações financeiras da TBO sejam pagas no prazo, dentro do orçamento aprovado e corretamente classificadas por centro de custo (BU). Evitar atrasos que gerem multas, manter relacionamento saudável com fornecedores e preservar previsibilidade do fluxo de caixa. Meta: 0% de pagamentos em atraso, 100% das despesas classificadas por CC.\n\n### 2. Escopo\n**Quem executa:** Responsável Financeiro TBO (ou Marco/Ruy para aprovações)\n**Quando se aplica:** Toda despesa operacional, nota fiscal recebida, fatura de fornecedor ou reembolso de colaborador\n**Limites:** Cobre contas a pagar e despesas. Faturamento/recebíveis → SOP tbo-fin-001. DRE mensal → SOP tbo-fin-003.\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Receber e registrar nota fiscal/fatura | Financeiro | — | — | — |\n| Classificar por centro de custo (BU) | Financeiro | — | Líder BU (se dúvida) | — |\n| Solicitar aprovação de pagamento | Financeiro | Marco/Ruy (por alçada) | — | — |\n| Efetuar pagamento | Financeiro | Marco Andolfato | — | Ops |\n| Conciliar com extrato bancário | Financeiro | — | — | Marco, Ruy |\n| Lançar no OMIE/sistema financeiro | Financeiro | — | — | — |\n| Aprovar despesas não orçadas | Marco Andolfato | Ruy Lima | Financeiro | — |\n| Relatório semanal de compromissos | Financeiro | — | — | Marco, Ruy |\n\n### 4. Pré-requisitos\n\n- [ ] Acesso ao OMIE (ERP financeiro) e conta bancária da TBO\n- [ ] Tabela de centros de custo atualizada (BRD, D3D, MKT, AV, INT, ADM, CORP)\n- [ ] Alçadas de aprovação definidas e comunicadas\n- [ ] Calendário de vencimentos configurado no OMIE\n- [ ] Fornecedores com dados bancários cadastrados\n\n### 5. Procedimento\n\n**5.1 Recebimento e Registro de Nota Fiscal/Fatura**\n\n1. Toda NF/fatura recebida (e-mail, portal, WhatsApp) deve ser registrada em até 24h\n2. Salvar no Google Drive: `Financeiro/[ANO]/[MÊS]/Contas-a-Pagar/`\n3. Nomenclatura: `AAAA-MM-DD_Fornecedor_Valor_CC.pdf`\n4. Lançar no OMIE com:\n   - Fornecedor\n   - Valor (R$)\n   - Data de vencimento\n   - Centro de custo (BU)\n   - Categoria de despesa (ver tabela de categorias)\n   - Número da NF\n   - Projeto relacionado (se aplicável)\n\n**5.2 Centros de Custo da TBO**\n\n| CC | BU | Exemplos de despesas |\n|---|---|---|\n| BRD | Branding | Fontes, plugins, impressões de apresentação, fonts.adobe.com |\n| D3D | Digital 3D | Software 3DS Max, V-Ray, Chaos Cloud, assets 3D, freelas 3D |\n| MKT | Marketing | Meta Ads, Google Ads, RD Station, Canva Pro, freelas de tráfego |\n| AV | Audiovisual | Equipamentos, aluguel de câmera, freelas de edição, músicas |\n| INT | Interiores | Software de interiores, visitas técnicas, freelas |\n| ADM | Administrativo | Aluguel, luz, internet, material de escritório, contador |\n| CORP | Corporativo | Viagens estratégicas, eventos, patrocínios, benefícios |\n\n**5.3 Alçadas de Aprovação**\n\n| Valor | Aprovador |\n|---|---|\n| Até R$ 500 | Financeiro (autonomia) |\n| R$ 501 - R$ 2.000 | Marco OU Ruy (qualquer um) |\n| R$ 2.001 - R$ 10.000 | Marco E Ruy (ambos) |\n| Acima de R$ 10.000 | Marco E Ruy + justificativa escrita |\n\n**5.4 Fluxo de Aprovação**\n\n1. Financeiro identifica despesa pendente de aprovação\n2. Encaminhar ao aprovador via WhatsApp ou e-mail com:\n   - Nome do fornecedor\n   - Descrição do serviço\n   - Valor\n   - Data de vencimento\n   - Centro de custo\n   - Projeto relacionado (se houver)\n3. Aguardar aprovação (prazo máximo: D-2 do vencimento)\n4. Se não aprovado em D-2: escalar com urgência\n5. Registrar aprovação no OMIE (nome do aprovador + data)\n\n**5.5 Pagamento**\n\n1. Pagar em até D-1 do vencimento (nunca no dia exato — evitar falhas bancárias)\n2. Prioridade de pagamento:\n   - **Crítico**: folha de pagamento, impostos, fornecedores estratégicos\n   - **Alto**: aluguéis, serviços recorrentes (SaaS, ferramentas)\n   - **Normal**: fornecedores de projeto, freelas\n   - **Baixo**: reembolsos, despesas administrativas menores\n3. Após pagamento: registrar comprovante no OMIE e na pasta do Drive\n4. Comunicar ao fornecedor quando solicitado\n\n**5.6 Controle de Reembolsos**\n\n1. Colaborador preenche formulário de reembolso com:\n   - Descrição da despesa\n   - Valor\n   - Data\n   - Centro de custo\n   - Comprovante anexado (nota fiscal ou recibo)\n2. Aprovação pelo líder da BU (< R$ 200) ou Marco/Ruy (≥ R$ 200)\n3. Pagamento no próximo ciclo de pagamentos (dia 15 ou dia 30)\n4. Limite de reembolso sem NF: R$ 50 por ocorrência, máx R$ 150/mês por colaborador\n\n**5.7 Rotina Semanal (toda segunda-feira)**\n\n1. Revisar todos os vencimentos da semana no OMIE\n2. Identificar aprovações pendentes\n3. Enviar relatório de compromissos da semana para Marco e Ruy:\n   - Total a pagar na semana (R$)\n   - Pagamentos críticos (vence em < 3 dias)\n   - Aprovações pendentes\n   - Saldo atual em conta\n4. Executar pagamentos aprovados\n\n**5.8 Conciliação Mensal**\n\n1. Executar na virada do mês (último dia útil)\n2. Comparar extrato bancário com lançamentos no OMIE\n3. Identificar e investigar divergências\n4. Gerar relatório de despesas por CC para o DRE (SOP tbo-fin-003)\n\n### 6. Checklist de Validação\n\n**Semanal:**\n- [ ] Todos os vencimentos da semana revisados no OMIE\n- [ ] Aprovações pendentes encaminhadas\n- [ ] Relatório enviado para Marco e Ruy (segunda-feira)\n- [ ] Pagamentos executados até D-1 do vencimento\n\n**Por transação:**\n- [ ] NF/fatura salva no Drive com nomenclatura correta\n- [ ] Lançada no OMIE com CC e categoria\n- [ ] Aprovação registrada (nome + data)\n- [ ] Comprovante de pagamento arquivado\n\n**Mensal:**\n- [ ] Conciliação bancária realizada\n- [ ] Divergências investigadas e resolvidas\n- [ ] Relatório por CC gerado para o DRE\n- [ ] 0% de pagamentos em atraso no mês\n\n### 7. Ferramentas e Recursos\n\n- **OMIE**: ERP financeiro principal (contas a pagar, NFs, conciliação)\n- **TBO OS — Módulo Financeiro**: visibilidade de centros de custo\n- **Google Drive**: arquivo de NFs e comprovantes\n- **Banco (app/internet banking)**: execução de pagamentos\n- **WhatsApp/e-mail**: fluxo de aprovações\n- **Planilha de Reembolsos**: Google Sheets compartilhada (link na pasta Financeiro)\n\n### 8. SLAs e Métricas\n\n| Métrica | Meta |\n|---|---|\n| Registro de NF/fatura após recebimento | ≤ 24h |\n| Antecedência de pagamento ao vencimento | D-1 (nunca no dia) |\n| Pagamentos em atraso por mês | 0% |\n| Despesas classificadas por CC | 100% |\n| Relatório semanal enviado | Toda segunda-feira |\n| Conciliação mensal realizada | Último dia útil do mês |\n| Tempo para aprovação de reembolso | ≤ 5 dias úteis |\n\n### 9. Troubleshooting\n\n**Fatura chegou no dia do vencimento:**\n→ Pagar imediatamente via PIX se aprovado\n→ Se > R$ 500: ligar para Marco/Ruy para aprovação verbal + registrar no OMIE\n→ Comunicar ao fornecedor sobre recebimento tardio\n\n**Aprovador não responde em D-2:**\n→ Tentativa 1: WhatsApp\n→ Tentativa 2: Ligação\n→ Se não obtiver resposta: escalar para o outro diretor\n→ Nunca deixar vencer por falta de aprovação\n\n**Despesa sem nota fiscal (fornecedor informal):**\n→ Solicitar RPA (Recibo de Pagamento Autônomo) ao fornecedor\n→ Se impossível: registrar como "despesa sem NF" com descrição detalhada\n→ Limite: máximo 5% do total mensal de despesas sem NF\n→ Alertar contador sobre despesas sem NF para orientação fiscal\n\n**Erro de classificação de CC identificado após pagamento:**\n→ Corrigir lançamento no OMIE com nota de justificativa\n→ Não reprocessar o pagamento — apenas ajustar o registro\n→ Comunicar ao líder da BU afetada\n\n**Saldo insuficiente para pagamentos da semana:**\n→ Priorizar pela ordem: folha > impostos > aluguel > fornecedores estratégicos\n→ Contatar Marco e Ruy imediatamente\n→ Negociar prazo com fornecedores não críticos (máximo 5 dias)\n\n### 10. Template Anexo\n\n**Template: Relatório Semanal de Compromissos**\n```markdown\n# Compromissos Financeiros — Semana de [DD/MM] a [DD/MM/AAAA]\n\n## Saldo Atual\n- Conta corrente principal: R$ ___\n- Conta corrente reserva: R$ ___\n\n## A Pagar Esta Semana\n| Vencimento | Fornecedor | Valor | CC | Status |\n|---|---|---|---|---|\n| DD/MM | | R$ | | ✅ Aprovado / ⏳ Aguardando |\n\n**Total a pagar: R$ ___**\n\n## Aprovações Pendentes\n| Fornecedor | Valor | Aprovador necessário | Urgência |\n|---|---|---|---|\n\n## Alertas\n- [ ] Pagamentos críticos (vence em < 3 dias):\n- [ ] Saldo abaixo do mínimo operacional (< R$ 20k):\n- [ ] Despesas não orçadas a validar:\n```\n\n**Template: Solicitação de Reembolso**\n```\nData: | Colaborador: | BU:\nDescrição da despesa:\nValor: R$ | Projeto relacionado:\nCC: BRD / D3D / MKT / AV / INT / ADM / CORP\nAnexo: [ ] NF | [ ] Recibo | [ ] Sem comprovante (motivo: ___)\nAprovação líder BU: [ ] Aprovado — ___/___/___\n```',
    '',
    'published',
    'critical',
    ARRAY['contas a pagar', 'despesas', 'financeiro', 'centro de custo', 'OMIE', 'pagamentos', 'fluxo de caixa', 'aprovação'],
    2,
    2
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    content = EXCLUDED.content,
    content_html = EXCLUDED.content_html,
    priority = EXCLUDED.priority,
    tags = EXCLUDED.tags,
    version = EXCLUDED.version,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-fin-002-contas-a-pagar-e-controle-de-despesas';
  DELETE FROM knowledge_sop_steps WHERE sop_id = v_sop_id;

  INSERT INTO knowledge_sop_steps (sop_id, title, content, content_html, order_index, step_type) VALUES
  (v_sop_id, 'Objetivo', E'Garantir que todas as obrigações financeiras TBO sejam pagas no prazo, dentro do orçamento aprovado e corretamente classificadas por centro de custo (BU). Meta: 0% de pagamentos em atraso, 100% das despesas classificadas por CC.', '', 0, 'step'),
  (v_sop_id, 'Escopo', E'**Quem executa:** Responsável Financeiro TBO + Marco/Ruy (aprovações)\n**Quando se aplica:** Toda despesa operacional, NF recebida, fatura de fornecedor ou reembolso\n**Limites:** Cobre contas a pagar. Recebíveis → SOP tbo-fin-001. DRE → SOP tbo-fin-003.', '', 1, 'step'),
  (v_sop_id, 'RACI — Responsabilidades', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Receber e registrar NF/fatura | Financeiro | — | — | — |\n| Classificar por centro de custo | Financeiro | — | Líder BU (dúvida) | — |\n| Solicitar aprovação de pagamento | Financeiro | Marco/Ruy (por alçada) | — | — |\n| Efetuar pagamento | Financeiro | Marco Andolfato | — | Ops |\n| Conciliar com extrato bancário | Financeiro | — | — | Marco, Ruy |\n| Lançar no OMIE | Financeiro | — | — | — |\n| Aprovar despesas não orçadas | Marco Andolfato | Ruy Lima | Financeiro | — |\n| Relatório semanal de compromissos | Financeiro | — | — | Marco, Ruy |', '', 2, 'step'),
  (v_sop_id, 'Pré-requisitos', E'- Acesso ao OMIE (ERP) e conta bancária da TBO\n- Tabela de CCs atualizada (BRD, D3D, MKT, AV, INT, ADM, CORP)\n- Alçadas de aprovação definidas (até R$500: Financeiro | R$501-2k: Marco ou Ruy | R$2k-10k: ambos | >R$10k: ambos + justificativa)\n- Calendário de vencimentos configurado no OMIE\n- Fornecedores com dados bancários cadastrados', '', 3, 'step'),
  (v_sop_id, 'Procedimento', E'**Por transação:**\n1. Registrar NF/fatura no Drive e no OMIE em ≤ 24h após recebimento\n2. Classificar por CC (BRD/D3D/MKT/AV/INT/ADM/CORP) e categoria\n3. Enviar para aprovação se acima da alçada do Financeiro\n4. Pagar em D-1 do vencimento (nunca no dia exato)\n5. Arquivar comprovante no Drive e no OMIE\n\n**Rotina semanal (segunda-feira):**\nRevisar vencimentos da semana → identificar aprovações pendentes → enviar relatório para Marco e Ruy → executar pagamentos aprovados.\n\n**Reembolsos:**\nFormulário preenchido com comprovante → aprovação líder BU (<R$200) ou Marco/Ruy (≥R$200) → pagamento no ciclo do dia 15 ou dia 30.\n\n**Conciliação mensal (último dia útil):**\nComparar extrato bancário × OMIE → investigar divergências → gerar relatório por CC para DRE.', '', 4, 'step'),
  (v_sop_id, 'Checklist de Validação', E'**Por transação:**\n- [ ] NF/fatura salva no Drive (nomenclatura: AAAA-MM-DD_Fornecedor_Valor_CC.pdf)\n- [ ] Lançada no OMIE com CC e categoria\n- [ ] Aprovação registrada (nome + data)\n- [ ] Pago em D-1 do vencimento\n- [ ] Comprovante arquivado\n\n**Semanal:**\n- [ ] Relatório enviado (segunda-feira)\n- [ ] Aprovações pendentes resolvidas\n- [ ] 0% de vencimentos perdidos\n\n**Mensal:**\n- [ ] Conciliação bancária realizada\n- [ ] Relatório por CC gerado para DRE\n- [ ] 0% de pagamentos em atraso', '', 5, 'checkpoint'),
  (v_sop_id, 'Ferramentas e Recursos', E'- **OMIE**: ERP financeiro principal (contas a pagar, NFs, conciliação)\n- **TBO OS — Módulo Financeiro**: visibilidade de centros de custo\n- **Google Drive**: `Financeiro/[ANO]/[MÊS]/Contas-a-Pagar/`\n- **Banco (internet banking/app)**: execução de pagamentos\n- **WhatsApp/e-mail**: fluxo de aprovações\n- **Google Sheets**: planilha de reembolsos compartilhada', '', 6, 'tip'),
  (v_sop_id, 'SLAs e Métricas', E'| Métrica | Meta |\n|---|---|\n| Registro de NF após recebimento | ≤ 24h |\n| Antecedência de pagamento | D-1 (nunca no dia) |\n| Pagamentos em atraso/mês | 0% |\n| Despesas classificadas por CC | 100% |\n| Relatório semanal | Toda segunda-feira |\n| Conciliação mensal | Último dia útil do mês |\n| Reembolso aprovado e pago | ≤ 5 dias úteis |', '', 7, 'note'),
  (v_sop_id, 'Troubleshooting', E'**Fatura chegou no dia do vencimento:** Pagar via PIX imediatamente. Se >R$500: aprovação verbal de Marco/Ruy + registrar no OMIE.\n\n**Aprovador não responde em D-2:** WhatsApp → ligação → outro diretor. Nunca deixar vencer por falta de aprovação.\n\n**Despesa sem NF (fornecedor informal):** Solicitar RPA. Se impossível: registrar como "despesa sem NF" com descrição. Limite: máx. 5% do total mensal. Alertar contador.\n\n**Saldo insuficiente para pagamentos da semana:** Priorizar: folha > impostos > aluguel > fornecedores estratégicos. Contatar Marco e Ruy imediatamente. Negociar prazo com fornecedores não críticos (máx. 5 dias).', '', 8, 'warning'),
  (v_sop_id, 'Templates Prontos para Uso', E'**Relatório Semanal de Compromissos:**\n```\nSemana de [DD/MM] a [DD/MM]\nSaldo atual: R$ ___\n\nA Pagar Esta Semana:\n| Vencimento | Fornecedor | Valor | CC | Status |\n|---|---|---|---|---|\n\nTotal: R$ ___\nAprovações pendentes: [lista]\nAlertas: [pagamentos críticos / saldo baixo]\n```\n\n**Solicitação de Reembolso:**\n```\nData: | Colaborador: | BU: | CC:\nDescrição: | Valor: R$ | Projeto:\nAnexo: NF / Recibo / Sem comprovante (motivo: ___)\nAprovação líder BU: ___/___/___\n```', '', 9, 'tip');

